parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "vendor_name": {
      "type": ["string", "null"],
      "description": "Legal name of the supplier issuing the invoice. Do not return the customer or bill-to company."
    },
    "vendor_tax_id": {
      "type": ["string", "null"],
      "description": "Supplier tax identification, VAT or registration number exactly as shown."
    },
    "invoice_number": {
      "type": ["string", "null"],
      "description": "Unique invoice number exactly as shown in the document."
    },
    "invoice_date": {
      "type": ["string", "null"],
      "description": "Invoice issue date formatted as YYYY-MM-DD."
    },
    "due_date": {
      "type": ["string", "null"],
      "description": "Payment due date formatted as YYYY-MM-DD."
    },
    "currency": {
      "type": ["string", "null"],
      "description": "Three-letter ISO 4217 currency code, for example EUR, USD or UAH."
    },
    "subtotal": {
      "type": ["number", "null"],
      "description": "Invoice subtotal before tax, as a number without currency symbols."
    },
    "tax_amount": {
      "type": ["number", "null"],
      "description": "Total tax or VAT amount, as a number without currency symbols."
    },
    "total_amount": {
      "type": ["number", "null"],
      "description": "Final total amount due. Use the amount explicitly labeled total due, invoice total or amount payable."
    },
    "account_holder": {
      "type": ["string", "null"],
      "description": "Name of the bank account holder."
    },
    "iban": {
      "type": ["string", "null"],
      "description": "IBAN in uppercase without spaces."
    },
    "swift_bic": {
      "type": ["string", "null"],
      "description": "SWIFT or BIC code in uppercase without spaces."
    },
    "bank_name": {
      "type": ["string", "null"],
      "description": "Name of the supplier bank."
    },
    "payment_reference": {
      "type": ["string", "null"],
      "description": "Payment reference requested by the supplier."
    },
    "confidence": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Overall extraction confidence from 0 to 1."
    },
    "missing_fields": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Names of important fields not found in the document."
    }
  },
  "required": [
    "vendor_name",
    "vendor_tax_id",
    "invoice_number",
    "invoice_date",
    "due_date",
    "currency",
    "subtotal",
    "tax_amount",
    "total_amount",
    "account_holder",
    "iban",
    "swift_bic",
    "bank_name",
    "payment_reference",
    "confidence",
    "missing_fields"
  ],
  "additionalProperties": false
}

parameters.jsCode:
const aiData = $json.output ?? $json;

const sourceItem =
  $('invoice__trigger--subworkflow').item;

const nativeExtraction =
  $('invoice__text--extract-pdf').item;

const nativeText = String(
  nativeExtraction?.json?.text ?? ''
).trim();

const nativeTextSufficient =
  nativeText.length >= 150 &&
  (
    nativeText.match(
      /[A-Za-zА-Яа-яІіЇїЄє0-9]/g
    )?.length ?? 0
  ) >= 80;

let documentText = nativeText;
let extractionMethod = 'native_pdf_text';

if (!nativeTextSufficient) {
  const ocrItem =
    $('invoice__ocr--normalize-text').item;

  const ocrText = String(
    ocrItem?.json?.text ?? ''
  ).trim();

  if (!ocrText) {
    throw new Error('OCR_NORMALIZED_TEXT_MISSING');
  }

  documentText = ocrText;
  extractionMethod = 'openai_pdf_ocr';
}

if (!sourceItem) {
  throw new Error('SOURCE_DOCUMENT_NOT_FOUND');
}

if (!aiData || typeof aiData !== 'object') {
  throw new Error('AI_EXTRACTION_OUTPUT_INVALID');
}

const normalizeText = (value) => {
  if (value === null || value === undefined) {
    return null;
  }

  const normalized = String(value)
    .replace(/\s+/g, ' ')
    .trim();

  return normalized || null;
};

const normalizeCode = (value) => {
  const normalized = normalizeText(value);

  return normalized
    ? normalized.toUpperCase().replace(/\s+/g, '')
    : null;
};

const normalizeAmount = (value) => {
  if (value === null || value === undefined || value === '') {
    return null;
  }

  const number = Number(value);

  return Number.isFinite(number)
    ? Math.round(number * 100) / 100
    : null;
};

const isValidIsoDate = (value) => {
  if (!value || !/^\d{4}-\d{2}-\d{2}$/.test(value)) {
    return false;
  }

  const date = new Date(`${value}T00:00:00Z`);

  return (
    !Number.isNaN(date.getTime()) &&
    date.toISOString().slice(0, 10) === value
  );
};

const vendorName = normalizeText(aiData.vendor_name);
const vendorTaxId = normalizeCode(aiData.vendor_tax_id);
const invoiceNumber = normalizeText(aiData.invoice_number);
const invoiceDate = normalizeText(aiData.invoice_date);
const dueDate = normalizeText(aiData.due_date);
const currency = normalizeCode(aiData.currency);

const subtotal = normalizeAmount(aiData.subtotal);
const taxAmount = normalizeAmount(aiData.tax_amount);
const totalAmount = normalizeAmount(aiData.total_amount);

const accountHolder = normalizeText(aiData.account_holder);
const iban = normalizeCode(aiData.iban);
const swiftBic = normalizeCode(aiData.swift_bic);
const bankName = normalizeText(aiData.bank_name);
const paymentReference = normalizeText(aiData.payment_reference);

const confidenceValue = Number(aiData.confidence);

const confidence = Number.isFinite(confidenceValue)
  ? Math.min(1, Math.max(0, confidenceValue))
  : 0;

const missingFields = new Set(
  Array.isArray(aiData.missing_fields)
    ? aiData.missing_fields.map(String)
    : []
);

const riskFlags = [];

const requiredFields = {
  vendor_name: vendorName,
  invoice_number: invoiceNumber,
  invoice_date: invoiceDate,
  due_date: dueDate,
  currency,
  total_amount: totalAmount,
  iban
};

for (const [fieldName, fieldValue] of Object.entries(requiredFields)) {
  if (
    fieldValue === null ||
    fieldValue === undefined ||
    fieldValue === ''
  ) {
    missingFields.add(fieldName);
  }
}

if (invoiceDate && !isValidIsoDate(invoiceDate)) {
  riskFlags.push('invalid_invoice_date');
}

if (dueDate && !isValidIsoDate(dueDate)) {
  riskFlags.push('invalid_due_date');
}

if (
  isValidIsoDate(invoiceDate) &&
  isValidIsoDate(dueDate) &&
  dueDate < invoiceDate
) {
  riskFlags.push('due_date_before_invoice_date');
}

if (totalAmount !== null && totalAmount <= 0) {
  riskFlags.push('invalid_total_amount');
}

if (currency && !/^[A-Z]{3}$/.test(currency)) {
  riskFlags.push('invalid_currency');
}

if (iban && !/^[A-Z]{2}[A-Z0-9]{13,32}$/.test(iban)) {
  riskFlags.push('invalid_iban_format');
}

if (
  subtotal !== null &&
  taxAmount !== null &&
  totalAmount !== null
) {
  const calculatedTotal =
    Math.round((subtotal + taxAmount) * 100) / 100;

  if (Math.abs(calculatedTotal - totalAmount) > 0.01) {
    riskFlags.push('total_amount_mismatch');
  }
}

if (confidence < 0.85) {
  riskFlags.push('low_extraction_confidence');
}

const invoiceIdVendorPart = (
  vendorTaxId ||
  vendorName ||
  'UNKNOWN'
)
  .toUpperCase()
  .replace(/[^A-Z0-9]/g, '')
  .slice(0, 30);

const invoiceIdNumberPart = (
  invoiceNumber ||
  sourceItem.json.processing_id
)
  .toUpperCase()
  .replace(/[^A-Z0-9-]/g, '')
  .slice(0, 50);

const invoiceId =
  `INV-${invoiceIdVendorPart}-${invoiceIdNumberPart}`;

const normalizedMissingFields = [...missingFields]
  .filter(Boolean)
  .sort();

const extractionValid =
  normalizedMissingFields.length === 0 &&
  riskFlags.length === 0;

return {
  json: {
    ...sourceItem.json,

    invoice_id: invoiceId,
    status: 'extracted',

    vendor_name: vendorName,
    vendor_tax_id: vendorTaxId,
    invoice_number: invoiceNumber,
    invoice_date: invoiceDate,
    due_date: dueDate,
    currency,

    subtotal,
    tax_amount: taxAmount,
    total_amount: totalAmount,

    account_holder: accountHolder,
    iban,
    swift_bic: swiftBic,
    bank_name: bankName,
    payment_reference: paymentReference,

    extraction_method: extractionMethod,
    extraction_confidence: confidence,
    extraction_valid: extractionValid,
    missing_fields: normalizedMissingFields,
    risk_flags: riskFlags,

    document_text: documentText,
    extracted_at: new Date().toISOString()
  },

  binary: sourceItem.binary
};

const extractionResult = $json;

const sourceItem =
  $('invoice__trigger--subworkflow').item;

if (!sourceItem) {
  throw new Error('SOURCE_DOCUMENT_NOT_FOUND');
}

if (!sourceItem.binary?.invoice_file) {
  throw new Error('INVOICE_BINARY_NOT_FOUND');
}

return {
  json: {
    ...sourceItem.json,
    native_extraction_pages:
      extractionResult.numpages ?? null,
    native_extraction_text:
      extractionResult.text ?? '',
    native_text_length:
      String(extractionResult.text ?? '').trim().length,
    ocr_required: true,
    status: 'ocr_pending',
    ocr_started_at: new Date().toISOString()
  },

  binary: {
    invoice_file: sourceItem.binary.invoice_file
  }
};

const sourceItem =
  $('invoice__document--restore-for-ocr').item;

if (!sourceItem) {
  throw new Error('OCR_SOURCE_DOCUMENT_NOT_FOUND');
}

const responseOutput = Array.isArray($json.output)
  ? $json.output
  : [];

const message = responseOutput.find(
  item =>
    item?.type === 'message' &&
    Array.isArray(item?.content)
);

const textContent = message?.content?.find(
  item =>
    item?.type === 'output_text' &&
    typeof item?.text === 'string'
);

const ocrText = String(textContent?.text ?? '').trim();

if (!ocrText) {
  throw new Error('OCR_TEXT_MISSING');
}

if (ocrText.length < 80) {
  throw new Error('OCR_TEXT_INSUFFICIENT');
}

return {
  json: {
    ...sourceItem.json,

    text: ocrText,
    extraction_method: 'openai_pdf_ocr',
    ocr_text_length: ocrText.length,
    ocr_completed_at: new Date().toISOString(),
    status: 'ocr_completed'
  },

  binary: sourceItem.binary
};
